class Solution:
    def maxConsecutiveAnswers(self, answerKey: str, k: int) -> int:
        n = len(answerKey)
        res = 0
        l = 0
        cntT, cntF = 0, 0
        for r in range(n):
            if answerKey[r] == 'T':
                cntT += 1
            else:
                cntF += 1
            while cntT > k and cntF > k:
                if answerKey[l] == 'T':
                    cntT -= 1
                else:
                    cntF -= 1
                l += 1
            res = max(res, cntT + cntF)
        return res

